#include <stdio.h>

/* == EXEMPLE ================================================
 * Parser une adresse IP:port avec sscanf
 * sscanf retourne le nombre de champs parses avec succes
 * =========================================================== */
void example_parse_ip(void) {
    char *addr = "192.168.1.42:8080";
    int a, b, c, d, port;
    int n = sscanf(addr, "%d.%d.%d.%d:%d", &a, &b, &c, &d, &port);
    if (n == 5) {
        printf("IP: %d.%d.%d.%d\n", a, b, c, d);
        printf("Port: %d\n", port);
    } else {
        printf("Parse error: got %d fields\n", n);
    }
}
/* Resultat: IP: 192.168.1.42 / Port: 8080 */

